// src/components/AudioUpload.js
import React, { useState } from 'react';
import axios from 'axios';

const AudioUpload = () => {
  const [file, setFile] = useState(null);
  const [uploadedFilePath, setUploadedFilePath] = useState('');
  const [waveformUrl, setWaveformUrl] = useState('');

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    const formData = new FormData();
    formData.append('audio', file);

    try {
      const response = await axios.post('http://localhost:5001/upload', formData);
      setUploadedFilePath(response.data.filePath);
    } catch (error) {
      console.error('Error uploading file:', error);
    }
  };

  const handleTrim = async (start, end) => {
    try {
      const response = await axios.post('http://localhost:5001/trim', {
        start,
        end,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error trimming audio:', error);
    }
  };

  const handleChangeSpeed = async (speed) => {
    try {
      const response = await axios.post('http://localhost:5001/change-speed', {
        speed,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error changing speed:', error);
    }
  };

  const handleChangePitch = async (pitch) => {
    try {
      const response = await axios.post('http://localhost:5001/change-pitch', {
        pitch,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error changing pitch:', error);
    }
  };

  const handleReverse = async () => {
    try {
      const response = await axios.post('http://localhost:5001/reverse', {
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error reversing audio:', error);
    }
  };

  const handleFade = async (fadeInDuration, fadeOutDuration) => {
    try {
      const response = await axios.post('http://localhost:5001/fade', {
        fadeInDuration,
        fadeOutDuration,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error applying fade effect:', error);
    }
  };

  const handleAddBackgroundMusic = async (bgMusicPath) => {
    try {
      const response = await axios.post('http://localhost:5001/add-background-music', {
        bgMusicPath,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error adding background music:', error);
    }
  };

  const handleApplyEffects = async (effect) => {
    try {
      const response = await axios.post('http://localhost:5001/apply-effects', {
        effect,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error applying effects:', error);
    }
  };

  const handleAdjustVolume = async (volume) => {
    try {
      const response = await axios.post('http://localhost:5001/adjust-volume', {
        volume,
        filePath: uploadedFilePath,
      });
      console.log(response.data);
    } catch (error) {
      console.error('Error adjusting volume:', error);
    }
  };

  const handleWaveform = async () => {
    try {
      const response = await axios.post('http://localhost:5001/waveform', {
        filePath: uploadedFilePath,
      });
      setWaveformUrl(response.data.path);
      console.log('Waveform generated:', response.data.path);
    } catch (error) {
      console.error('Error generating waveform:', error);
    }
  };

  return (
    <div className="audio-controls">
      <input type="file" accept="audio/mp3" onChange={handleFileChange} />
      <button onClick={handleUpload} disabled={!file}>
        Upload Audio
      </button>

      {uploadedFilePath && (
        <>
          <h3>Uploaded Audio: {uploadedFilePath}</h3>

          <div>
            <h3>Trim Audio</h3>
            <button onClick={() => handleTrim(30, 60)}>Trim 30s to 60s</button>
          </div>

          <div>
            <h3>Change Speed</h3>
            <button onClick={() => handleChangeSpeed(1.5)}>Increase Speed (1.5x)</button>
          </div>

          <div>
            <h3>Change Pitch</h3>
            <button onClick={() => handleChangePitch(1.2)}>Increase Pitch (1.2x)</button>
          </div>

          <div>
            <h3>Reverse Audio</h3>
            <button onClick={handleReverse}>Reverse Audio</button>
          </div>

          <div>
            <h3>Apply Fade Effect</h3>
            <button onClick={() => handleFade(2, 2)}>Apply Fade In/Out (2s)</button>
          </div>

          <div>
            <h3>Add Background Music</h3>
            <button onClick={() => handleAddBackgroundMusic('/path/to/bgMusic.mp3')}>Add Background Music</button>
          </div>

          <div>
            <h3>Apply Effects</h3>
            <button onClick={() => handleApplyEffects('reverb')}>Apply Reverb</button>
          </div>

          <div>
            <h3>Adjust Volume</h3>
            <button onClick={() => handleAdjustVolume(0.8)}>Reduce Volume (80%)</button>
          </div>

          <div className="waveform-container">
            <h3>Generate Waveform</h3>
            <button onClick={handleWaveform}>Generate Waveform</button>
            {waveformUrl && <img src={`http://localhost:5001/${waveformUrl}`} alt="Waveform" />}
          </div>
        </>
      )}
    </div>
  );
};

export default AudioUpload;
